plugin.executeCode:
const words = input.trim().split(/\s+/).filter(Boolean).length;
const chars = input.length;
const sentences = (input.match(/[.!?]+/g) || []).length || 1;
const slow = Math.ceil(words / 150);
const avg  = Math.ceil(words / 238);
const fast = Math.ceil(words / 350);
function fmt(mins) {
  if (mins < 1) return 'less than a minute';
  return mins === 1 ? '1 minute' : mins + ' minutes';
}
const lines = [
  'Word count:    ' + words,
  'Character count: ' + chars,
  'Sentences:     ' + sentences,
  '',
  'Estimated Reading Time',
  '  Slow  (150 wpm): ' + fmt(slow),
  '  Avg   (238 wpm): ' + fmt(avg),
  '  Fast  (350 wpm): ' + fmt(fast),
];
return { output: lines.join('\n'), outputLanguage: 'text' };
